fun logMessage(
    message: String,
    level: String = "INFO",
    timestamp: Boolean = true
) {
    val prefix = if (timestamp) "[${System.currentTimeMillis()}]" else ""
    println("$prefix [$level] $message")
}

fun main() {
    logMessage("System started")
    logMessage("User logged in", "DEBUG")
    logMessage("Critical error", level = "ERROR", timestamp = false)
}
